// 暂存 GitHub repos 数据，传递给下一步
const repos = $input.first().json;
return [{json: {repos: Array.isArray(repos) ? repos : []}}];

const pypiData = $input.first().json || {};
const repos = $('暂存仓库数据').first().json.repos || [];

const currentVersion = '2.1.0';
const latestPyPI = pypiData.info?.version || currentVersion;
const hasNewVersion = latestPyPI !== currentVersion;

const now = new Date();
const oneDayAgo = new Date(now - 24 * 60 * 60 * 1000);
const oneWeekAgo = new Date(now - 7 * 24 * 60 * 60 * 1000);

const recentRepos = repos.filter(r => {
  const updated = new Date(r.updated_at || r.pushed_at);
  return updated > oneWeekAgo;
});

const skillRepos = repos.filter(r => {
  const name = (r.name || '').toLowerCase();
  const desc = (r.description || '').toLowerCase();
  return name.includes('skill') || name.includes('plugin') || name.includes('connector') ||
         desc.includes('skill') || desc.includes('plugin') || desc.includes('agent');
});

const reposUpdated24h = repos.filter(r => {
  const updated = new Date(r.updated_at || r.pushed_at);
  return updated > oneDayAgo;
});

let shouldNotify = false;
let msg = `🐙 rragents GitHub 巡检 ${now.toLocaleDateString()}\n`;
msg += `━━━━━━━━━━━━━━━━━━\n`;

if (hasNewVersion) {
  shouldNotify = true;
  msg += `\n🆕 openclaw-sdk 有新版本!\n`;
  msg += `  当前: v${currentVersion} → 最新: v${latestPyPI}\n`;
  msg += `  建议: pip install --upgrade openclaw-sdk\n`;
  const releases = pypiData.releases || {};
  const latestRelease = releases[latestPyPI];
  if (latestRelease && latestRelease.length > 0) {
    msg += `  发布时间: ${latestRelease[0].upload_time || ''}\n`;
  }
} else {
  msg += `\n📦 openclaw-sdk v${currentVersion} (最新)\n`;
}

if (recentRepos.length > 0) {
  shouldNotify = true;
  msg += `\n📂 近7天活跃仓库 (${recentRepos.length}个):\n`;
  recentRepos.slice(0, 8).forEach(r => {
    const updated = new Date(r.updated_at || r.pushed_at).toLocaleDateString();
    msg += `  • ${r.name} ⭐${r.stargazers_count || 0} (${updated})\n`;
    if (r.description) msg += `    ${r.description.substring(0, 60)}\n`;
  });
}

if (skillRepos.length > 0) {
  shouldNotify = true;
  msg += `\n🧩 Skills/Plugin 仓库:\n`;
  skillRepos.forEach(r => {
    msg += `  • ${r.name}: ${(r.description || '无描述').substring(0, 80)}\n`;
    msg += `    ${r.html_url}\n`;
  });
  msg += `\n💡 建议: 评估以上 skills 是否适合部署到 rragents`;
}

if (reposUpdated24h.length > 0) {
  msg += `\n🔄 24h内更新: ${reposUpdated24h.map(r => r.name).join(', ')}\n`;
}

if (!shouldNotify) {
  msg += `\n✅ 无新版本或更新`;
}

return [{json: {message: msg, shouldNotify, hasNewVersion, recentCount: recentRepos.length, skillCount: skillRepos.length}}];
